esqlQuery.esql:
TS metrics-oracledbreceiver.otel-*
// enqueue_deadlocks is a cumulative counter; INCREASE gives new deadlocks in window
| WHERE oracledb.enqueue_deadlocks IS NOT NULL
| STATS delta = SUM(INCREASE(oracledb.enqueue_deadlocks))
        BY oracledb.instance.name, host.name
// Alert on any increase — deadlocks cause ORA-00060 and rolled-back transactions
// INCREASE handles counter resets on instance restart
| WHERE delta > 0
| SORT delta DESC
